Bash(node -e "
const fs = require\(''fs''\);
const path = require\(''path''\);

// Check for any env files
const files = [''.env'', ''.env.local'', ''.env.production'', ''.secrets''];
const found = {};

files.forEach\(file => {
  if \(fs.existsSync\(file\)\) {
    const content = fs.readFileSync\(file, ''utf8''\);
    if \(content.includes\(''NEON_CONNECTION_STRING=postgresql://''\)\) {
      found.neon = ''Real connection string found'';
    } else if \(content.includes\(''NEON_CONNECTION_STRING''\)\) {
      found.neon = ''Variable exists but empty'';
    }

    if \(content.includes\(''SUPABASE_URL=https://''\)\) {
      found.supabase = ''Real URL found'';
    } else if \(content.includes\(''SUPABASE_URL''\)\) {
      found.supabase = ''Variable exists but empty'';
    }
  }
}\);

console.log\(JSON.stringify\(found, null, 2\)\);
")
